import { PATH_ELEMENT } from '../../../../core/element-constants';
import { d3_line } from '../../../../core/d3-constants';
import { getPoints } from '../../../../legend/size-legend/slider/slider-connector-parser';
import { getHandleData } from '../../../../legend/size-legend/slider/size-slider-helpers';

let line = d3_line();

function styleConnector(behaviourEventInstance, selectionManager, selection) {
    let point = selectionManager.point,
        _instance = behaviourEventInstance.instance,
        { options } = _instance,
        { component } = options,
        { element, brushOptions } = component;

    let connectorEle = element.selectAll(`${PATH_ELEMENT}.zc-connector-line`),
        data = getHandleData(brushOptions, point);

    connectorEle.attr('d', line(getPoints(component._parser.connectorSpec)(data, selection))); // TODO: check component._parser
}

export { styleConnector };
